# ANTI-PATTERN: Aggressive Fine-tuning (causes catastrophic forgetting)
class CricketBatsmanClassifier_BadPractice:
    def __init__(self, pretrained_model):
        self.model = pretrained_model

    def train_on_target(self, target_data):
        # WRONG: Unfreezes ALL layers immediately
        for param in self.model.parameters():
            param.requires_grad = True

        # High learning rate on small dataset → overwrites source knowledge
        optimizer = torch.optim.SGD(self.model.parameters(), lr=0.1)

        for epoch in range(50):
            for batch in target_data:
                loss = self.compute_loss(batch)
                loss.backward()
                optimizer.step()
        return self.model

# BEST PRACTICE: Progressive Unfreezing with Discriminative LR
class CricketBatsmanClassifier_BestPractice:
    def __init__(self, pretrained_model):
        self.model = pretrained_model
        self.layers = list(self.model.children())

    def train_progressive(self, target_data, num_stages=3):
        # Stage 1: Freeze backbone, train only classification head
        self._freeze_until_layer(freeze_until=len(self.layers)-1)
        self._train_stage(target_data, lr=0.001, epochs=20)

        # Stage 2: Unfreeze middle layers with lower learning rate
        self._freeze_until_layer(freeze_until=len(self.layers)//2)
        # Use discriminative learning rates: deeper layers get lower LR
        layer_groups = self._create_layer_groups()
        optimizer = torch.optim.AdamW([
            {'params': layer_groups[0], 'lr': 1e-5},
            {'params': layer_groups[1], 'lr': 1e-4},
            {'params': layer_groups[2], 'lr': 1e-3}
        ])
        self._train_stage(target_data, optimizer, epochs=15)

        # Stage 3: Fine-tune all layers with very low learning rate
        self._freeze_until_layer(freeze_until=0)
        optimizer = torch.optim.AdamW(self.model.parameters(), lr=1e-5)
        self._train_stage(target_data, optimizer, epochs=10)

        return self.model

    def _freeze_until_layer(self, freeze_until):
        for i, layer in enumerate(self.layers):
            if i < freeze_until:
                for param in layer.parameters():
                    param.requires_grad = False
            else:
                for param in layer.parameters():
                    param.requires_grad = True

    def _create_layer_groups(self):
        # Group early, middle, and late layers for discriminative LR
        return [
            list(self.layers[0].parameters()),
            list(self.layers[1].parameters()),
            list(self.layers[2].parameters())
        ]
